string findShortestCommonSupersequence(string firstString, string secondString) {

 int m=firstString.size();
 int n=secondString.size();
 if(m==0||n==0) return "";
 int d;
 string temp="";
 string def="";
 string first="";
 for(int i=0;i<n;i++){
  if(firstString[m-1]==secondString[i]){
   d=m-1;
   for(int k=m-1;k>0;k--){
    if(secondString[i]==firstString[k-1]){
     d=k-1;
    }
    else {
     break;
    }
   }
   for(int j=i+1;j<n;j++){
    temp.push_back(secondString[j]);
   }
   break;
  }
 }
 for(int j=0;j<=d;j++){
  first.push_back(firstString[j]);
 }

 return first+temp;
}

string findShortestCommonSupersequence(string firstString, string secondString) {
 int n=firstString.length();
 int m=secondString.length();

 vector<vector<int>>dp(n+1,vector<int>(m+1,0));

 for(int i=1;i<=n;i++)
 {

  for(int j=1;j<=m;j++)
  {
   if(firstString[i-1]==secondString[j-1])
   {
    dp[i][j]=1+dp[i-1][j-1];
   }
   else dp[i][j]=max(dp[i-1][j],dp[i][j-1]);
  }
 }
 int i=n;
 int j=m;
 string res="";
 while(i>0&&j>0)
 {
  if(firstString[i-1]==secondString[j-1])
  {
   res+=firstString[i-1];
   i--;
   j--;
  }
  else if ( dp[i-1][j]>dp[i][j-1])
   {
    res+=firstString[i-1];
    i--;
   }

  else {
  res+=secondString[j-1];
  j--;

  }
 }
 while(i>0)
 {
  res+=firstString[i-1];
  i--;
 }
 while(j>0)
 {
  res+=secondString[j-1];
  j--;
 }
 // reverse(res.begin(),res.end());
 string ans;
 for(int i=res.length()-1;i>=0;i--)
 {
  ans+=res[i];
 }
 return ans;
}

string findShortestCommonSupersequence(string firstString, string secondString) {
 int x= firstString.length();
 int y= secondString.length();
 vector<vector<int>> dp(x+1,vector<int>(y+1,0));
 for(int i=1;i<=x;i++){
  for(int j=1;j<=y;j++){
   if(firstString[i-1]==secondString[j-1]){
    dp[i][j]=1+dp[i-1][j-1];
   }
   else{
    dp[i][j]=max(dp[i-1][j],dp[i][j-1]);
   }
  }
 }
  int i=x;
  int j=y;
  string res="";
  while(i>0 && j>0){
   if(firstString[i-1]==secondString[j-1]){
    res+=firstString[i-1];
   i--;
   j--;
   }
   else if(dp[i-1][j]>dp[i][j-1]){
    res+=firstString[i-1];
    i--;
   }
   else{
    res+=secondString[j-1];
    j--;
   }
 }
   while(i>0){
    res+=firstString[i-1];
    i--;
   }
   while(j>0){
    res+=secondString[j-1];
    j--;
   }
   reverse(res.begin(),res.end());
   return res;

}
